import React, { useState, useEffect } from 'react';
import axios from 'axios';

const topics = ['All', 'Watering', 'Potting', 'Pest Control', 'Light'];

function CareTipsList({ onSelect }) {
  const [careTips, setCareTips] = useState([]);
  const [filter, setFilter] = useState('All');

  useEffect(() => {
    const fetchTips = async () => {
      let url = 'http://localhost:5000/api/caretips';
      if (filter !== 'All') {
        url += `?topic=${filter}`;
      }
      try {
        const res = await axios.get(url);
        setCareTips(res.data);
      } catch {
        alert('Failed to load care tips');
      }
    };
    fetchTips();
  }, [filter]);

  return (
    <div>
      <h2>Plant Care Tips</h2>
      <div>
        {topics.map(t => (
          <button
            key={t}
            onClick={() => setFilter(t)}
            style={{
              margin: '5px',
              backgroundColor: filter === t ? 'green' : 'lightgray',
              color: filter === t ? 'white' : 'black',
            }}
          >
            {t}
          </button>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(280px,1fr))', gap: '20px', marginTop: '20px' }}>
        {careTips.map(tip => (
          <div key={tip._id} style={{ border: '1px solid #ccc', padding: '15px' }}>
            <img src={tip.thumbnailUrl} alt={tip.title} style={{ width: '100%', height: '150px', objectFit: 'cover' }} />
            <h3>{tip.title}</h3>
            <p>{tip.summary}</p>
            <button onClick={() => onSelect(tip._id)}>Read More →</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default CareTipsList;
